1	import { readFile, stat } from "node:fs/promises";
2	import path from "node:path";
3	
4	export const EVIDENCE_FRESHNESS_POLICY_PATH = ".bandit/policy/evidence-freshness-slos.json";
5	const TEMPLATE_PATH = "docs/templates/evidence-freshness-slos.md";
6	
7	const REQUIRED_TEMPLATE_FIELDS = [
8	  "work_item",
9	  "policy",
10	  "artifact_types",
11	  "trust_signal_requirements",
12	  "derived_projection_rules",
13	  "source_artifacts"
14	];
15	
16	const REQUIRED_ARTIFACT_TYPES = [
17	  "tests",
18	  "coderabbit_review",
19	  "local_qwen_review",
20	  "landing_verdict",
21	  "derived_projection"
22	];
23	
24	const REQUIRED_TRUST_SIGNAL_REQUIREMENTS = [
25	  "source_artifact",
26	  "owner_or_authority_role",
27	  "freshness_state",
28	  "staleness_reason"
29	];
30	
31	type RawRecord = Record<string, unknown>;
32	
33	export type EvidenceTrustSignal = {
34	  artifact_type: string;
35	  source: string;
36	  owner_or_authority_role: string;
37	  freshness_state: EvidenceFreshnessState;
38	  staleness_reason: string;
39	  evidence_slo: string;
40	};
41	
42	export type EvidenceFreshnessState = "current" | "stale" | "missing";
43	
44	export type EvidenceFreshnessValidationReport = {
45	  status: "pass";
46	  policy: string;
47	  artifact_types: string[];
48	  trust_signal_requirements: string[];
49	  derived_projections: string[];
50	};
51	
52	export async function validateEvidenceFreshnessSlos(
53	  repoRoot: string
54	): Promise<EvidenceFreshnessValidationReport> {
55	  await validateTemplate(repoRoot);
56	  const content = await readRequiredPolicy(repoRoot);
57	  return parseAndValidatePolicy(content);
58	}
59	
60	export async function validateEvidenceFreshnessSlosPolicy(repoRoot: string): Promise<void> {
61	  const content = await readOptionalPolicy(repoRoot);
62	  if (content === null) return;
63	
64	  await validateTemplate(repoRoot);
65	  parseAndValidatePolicy(content);
66	}
67	
68	export async function evidenceFreshnessPolicyExists(repoRoot: string): Promise<boolean> {
69	  return pathExists(repoRoot, EVIDENCE_FRESHNESS_POLICY_PATH);
70	}
71	
72	export function buildGateTrustSignal(
73	  artifactType: string,
74	  source: string,
75	  ownerOrAuthorityRole: string,
76	  fileExistsOrFreshnessState: boolean | EvidenceFreshnessState,
77	  stalenessReason?: string
78	): Omit<EvidenceTrustSignal, "evidence_slo"> {
79	  // Projection builders add the fixed policy provenance through withEvidenceSlo.
80	  const freshnessState = resolveFreshnessState(fileExistsOrFreshnessState);
81	
82	  return {
83	    artifact_type: artifactType,
84	    source,
85	    owner_or_authority_role: ownerOrAuthorityRole,
86	    freshness_state: freshnessState,
87	    staleness_reason: stalenessReason ?? defaultStalenessReason(freshnessState)
88	  };
89	}
90	
91	export function withEvidenceSlo(
92	  signal: Omit<EvidenceTrustSignal, "evidence_slo">
93	): EvidenceTrustSignal {
94	  return {
95	    ...signal,
96	    evidence_slo: EVIDENCE_FRESHNESS_POLICY_PATH
97	  };
98	}
99	
100	export function readScalarStatus(content: string, key: string): string | null {
101	  const escapedKey = escapeRegExp(key);
102	  const match = content.match(new RegExp(`^${escapedKey}:\\s*(.+)$`, "m"));
103	  return match?.[1]?.trim() ?? null;
104	}
105	
106	export async function pathExists(repoRoot: string, displayPath: string): Promise<boolean> {
107	  try {
108	    await stat(path.join(repoRoot, displayPath));
109	    return true;
110	  } catch (error) {
111	    if (isMissingPathError(error)) return false;
112	    throw error;
113	  }
114	}
115	
116	function resolveFreshnessState(
117	  fileExistsOrFreshnessState: boolean | EvidenceFreshnessState
118	): EvidenceFreshnessState {
119	  if (typeof fileExistsOrFreshnessState !== "boolean") {
120	    return fileExistsOrFreshnessState;
121	  }
122	  return fileExistsOrFreshnessState ? "current" : "missing";
123	}
124	
125	function defaultStalenessReason(freshnessState: EvidenceFreshnessState): string {
126	  if (freshnessState === "current") return "none";
127	  if (freshnessState === "missing") return "missing_required_stage_evidence";
128	  return "stale_dependency";
129	}
130	
131	async function validateTemplate(repoRoot: string) {
132	  const templatePath = path.join(repoRoot, TEMPLATE_PATH);
133	  let content: string;
134	  try {
135	    content = await readFile(templatePath, "utf8");
136	  } catch (error) {
137	    if (isMissingPathError(error)) {
138	      throw new Error(`Missing required template: ${TEMPLATE_PATH}`);
139	    }
140	    throw error;
141	  }
142	
143	  const missingFields = REQUIRED_TEMPLATE_FIELDS.filter(
144	    (field) => !new RegExp(`^\\s*(?:-\\s*)?${escapeRegExp(field)}:`, "im").test(content)
145	  );
146	
147	  if (missingFields.length > 0) {
148	    throw new Error(
149	      `Malformed template: ${TEMPLATE_PATH}; missing required fields: ${missingFields.join(", ")}`
150	    );
151	  }
152	}
153	
154	async function readRequiredPolicy(repoRoot: string): Promise<string> {
155	  const content = await readPolicyFile(repoRoot);
156	  if (content === null) {
157	    throw new Error(`Missing required policy: ${EVIDENCE_FRESHNESS_POLICY_PATH}`);
158	  }
159	  return content;
160	}
161	
162	async function readOptionalPolicy(repoRoot: string): Promise<string | null> {
163	  return readPolicyFile(repoRoot);
164	}
165	
166	async function readPolicyFile(repoRoot: string): Promise<string | null> {
167	  const policyPath = path.join(repoRoot, EVIDENCE_FRESHNESS_POLICY_PATH);
168	  try {
169	    return await readFile(policyPath, "utf8");
170	  } catch (error) {
171	    if (isMissingPathError(error)) return null;
172	    throw error;
173	  }
174	}
175	
176	function parseAndValidatePolicy(content: string): EvidenceFreshnessValidationReport {
177	  let parsed: unknown;
178	  try {
179	    parsed = JSON.parse(content);
180	  } catch {
181	    throw new Error("Malformed evidence freshness SLO policy: invalid JSON");
182	  }
183	
184	  if (!isRecord(parsed)) {
185	    throw new Error("Malformed evidence freshness SLO policy: expected object");
186	  }
187	
188	  if (!Object.hasOwn(parsed, "contract_version")) {
189	    throw new Error("Malformed evidence freshness SLO policy: missing contract_version 1");
190	  }
191	
192	  if (parsed.contract_version !== 1) {
193	    throw new Error("Malformed evidence freshness SLO policy: contract_version must be 1");
194	  }
195	
196	  if (parsed.policy_id !== "evidence-freshness-slos") {
197	    throw new Error(
198	      "Malformed evidence freshness SLO policy: policy_id must be evidence-freshness-slos"
199	    );
200	  }
201	
202	  const artifactTypeIds = validateArtifactTypes(parsed);
203	  const trustSignalRequirements = collectTrustSignalRequirements(parsed);
204	  const derivedProjections = validateDerivedProjectionRules(parsed);
205	
206	  return {
207	    status: "pass",
208	    policy: EVIDENCE_FRESHNESS_POLICY_PATH,
209	    artifact_types: artifactTypeIds,
210	    trust_signal_requirements: trustSignalRequirements,
211	    derived_projections: derivedProjections
212	  };
213	}
214	
215	function validateArtifactTypes(policy: RawRecord): string[] {
216	  if (!Array.isArray(policy.artifact_types) || policy.artifact_types.length === 0) {
217	    throw new Error(
218	      "Malformed evidence freshness SLO policy: artifact_types must define required trusted evidence types"
219	    );
220	  }
221	
222	  const ids: string[] = [];
223	
224	  for (const item of policy.artifact_types as unknown[]) {
225	    if (!isRecord(item)) {
226	      throw new Error("Malformed evidence freshness SLO policy: artifact_types entries must be objects");
227	    }
228	
229	    const id = requireNonEmptyString(
230	      item.id,
231	      "evidence freshness SLO artifact types require a non-empty string id"
232	    );
233	
234	    const hasSourceArtifacts =
235	      Array.isArray(item.source_artifacts) &&
236	      (item.source_artifacts as unknown[]).length > 0;
237	    const hasOwner =
238	      (typeof item.owner === "string" && item.owner.trim().length > 0) ||
239	      (typeof item.authority_role === "string" && item.authority_role.trim().length > 0);
240	
241	    if (!hasSourceArtifacts || !hasOwner) {
242	      throw new Error(
243	        `evidence freshness SLO ${id} requires source artifact and owner or authority role`
244	      );
245	    }
246	
247	    if (Array.isArray(item.allowed_freshness_states)) {
248	      const states = item.allowed_freshness_states as unknown[];
249	      if (
250	        !states.includes("current") ||
251	        !states.includes("stale") ||
252	        !states.includes("missing")
253	      ) {
254	        throw new Error(
255	          "freshness states must include current, stale, and missing for trusted evidence signals"
256	        );
257	      }
258	    }
259	
260	    if (Array.isArray(item.staleness_reasons)) {
261	      if ((item.staleness_reasons as unknown[]).length === 0) {
262	        throw new Error(
263	          "trusted evidence signals require explicit staleness reason behavior"
264	        );
265	      }
266	    }
267	
268	    ids.push(id);
269	  }
270	
271	  const missingTypes = REQUIRED_ARTIFACT_TYPES.filter((id) => !ids.includes(id));
272	  if (missingTypes.length > 0) {
273	    throw new Error(
274	      `Malformed evidence freshness SLO policy: missing required artifact_types: ${missingTypes.join(", ")}`
275	    );
276	  }
277	
278	  return ids;
279	}
280	
281	function collectTrustSignalRequirements(policy: RawRecord): string[] {
282	  if (
283	    !Array.isArray(policy.trust_signal_requirements) ||
284	    policy.trust_signal_requirements.length === 0
285	  ) {
286	    throw new Error(
287	      "Malformed evidence freshness SLO policy: trust_signal_requirements must define required trust signal fields"
288	    );
289	  }
290	
291	  const requirements = (policy.trust_signal_requirements as unknown[]).map(
292	    (item) =>
293	      requireNonEmptyString(
294	        item,
295	        "Malformed evidence freshness SLO policy: trust_signal_requirements entries must be non-empty strings"
296	      )
297	  );
298	
299	  const missingRequirements = REQUIRED_TRUST_SIGNAL_REQUIREMENTS.filter(
300	    (requirement) => !requirements.includes(requirement)
301	  );
302	  if (missingRequirements.length > 0) {
303	    throw new Error(
304	      `Malformed evidence freshness SLO policy: missing required trust_signal_requirements: ${missingRequirements.join(", ")}`
305	    );
306	  }
307	
308	  return requirements;
309	}
310	
311	function validateDerivedProjectionRules(policy: RawRecord): string[] {
312	  if (
313	    !Array.isArray(policy.derived_projection_rules) ||
314	    policy.derived_projection_rules.length === 0
315	  ) {
316	    throw new Error(
317	      "Malformed evidence freshness SLO policy: derived_projection_rules must define fail-closed projection rules"
318	    );
319	  }
320	
321	  const projections: string[] = [];
322	
323	  for (const item of policy.derived_projection_rules as unknown[]) {
324	    if (!isRecord(item)) {
325	      throw new Error(
326	        "Malformed evidence freshness SLO policy: derived_projection_rules entries must be objects"
327	      );
328	    }
329	
330	    const projection = requireNonEmptyString(
331	      item.projection,
332	      "derived projection rules require a non-empty projection id"
333	    );
334	    requireNonEmptyStringList(
335	      item.source_artifacts,
336	      "derived projection rules require source artifacts"
337	    );
338	    requireNonEmptyStringList(
339	      item.dependent_evidence,
340	      "derived projection rules require dependent evidence"
341	    );
342	
343	    if (
344	      item.propagate_missing_or_stale_dependencies !== true ||
345	      item.cannot_upgrade_missing_dependency_to_trusted !== true
346	    ) {
347	      throw new Error(
348	        "derived projections must propagate missing or stale source dependencies and cannot upgrade them to trusted status"
349	      );
350	    }
351	
352	    projections.push(projection);
353	  }
354	
355	  return projections;
356	}
357	
358	function requireNonEmptyString(value: unknown, message: string): string {
359	  if (typeof value !== "string" || value.trim().length === 0) {
360	    throw new Error(message);
361	  }
362	  return value.trim();
363	}
364	
365	function requireNonEmptyStringList(value: unknown, message: string): string[] {
366	  if (
367	    !Array.isArray(value) ||
368	    value.length === 0 ||
369	    !value.every((item) => typeof item === "string" && item.trim().length > 0)
370	  ) {
371	    throw new Error(message);
372	  }
373	  return value.map((item) => item.trim());
374	}
375	
376	function escapeRegExp(value: string): string {
377	  return value.replace(/[.*+?^${}()|[\]\\]/g, "\\$&");
378	}
379	
380	function isRecord(value: unknown): value is RawRecord {
381	  return Boolean(value && typeof value === "object" && !Array.isArray(value));
382	}
383	
384	function isMissingPathError(error: unknown): boolean {
385	  return (
386	    error instanceof Error &&
387	    "code" in error &&
388	    (error as NodeJS.ErrnoException).code === "ENOENT"
389	  );
390	}
391

