463	function requireLabeledText(content: string, label: string, source: string) {
464	  const lines = content.split(/\r?\n/);
465	  const prefix = `**${label}:**`;
466	  const startIndex = lines.findIndex((line) => line.trim().startsWith(prefix));
467	
468	  if (startIndex === -1) {
469	    throw new Error(`Session context blocked: ${source} is missing ${label}`);
470	  }
471	
472	  const firstLine = lines[startIndex];
473	  if (!firstLine) {
474	    throw new Error(`Session context blocked: ${source} is missing ${label}`);
475	  }
476	
477	  const parts = [firstLine.slice(firstLine.indexOf(prefix) + prefix.length)];
478	  for (const line of lines.slice(startIndex + 1)) {
479	    const trimmed = line.trim();
480	    if (trimmed.length === 0 || trimmed.startsWith("## ") || trimmed.startsWith("**")) {
481	      break;
482	    }
483	    parts.push(trimmed);
484	  }
485	
486	  const text = normalizeText(parts.join(" "));
487	  if (!text) {
488	    throw new Error(`Session context blocked: ${source} has empty ${label}`);
489	  }
490	  return text;
491	}
