503	function readRequiredOperatorInput(content: string) {
504	  const section =
505	    content.match(/## Required Operator Input\s+([\s\S]*?)(?:\n## |\s*$)/)?.[1] ?? "";
506	  return /No operator-owned input is required/i.test(section)
507	    ? ("none_required" as const)
508	    : ("required" as const);
