511	function extractForbiddenActions(content: string) {
512	  const activeWorkSection =
513	    content.match(/## Active Work\s+([\s\S]*?)(?:\n## |\s*$)/)?.[1] ?? "";
514	  const normalizedSection = activeWorkSection.replace(/\r?\n/g, " ");
515	  const doNotMatch = normalizedSection.match(/Do not start ([^.]+)\./);
516	  if (!doNotMatch?.[1]) {
517	    return [];
518	  }
519	  return [`Do not start ${normalizeText(doNotMatch[1])}.`];
520	}
