522	function parseBootstrapGapsRaw(content: string): RawGap[] {
523	  let parsed: unknown;
524	  try {
525	    parsed = JSON.parse(content);
526	  } catch {
527	    throw new Error("Session context blocked: malformed bootstrap gap ledger");
528	  }
529	  if (!isRecord(parsed) || !Array.isArray(parsed.gaps)) {
530	    throw new Error("Session context blocked: malformed bootstrap gap ledger");
531	  }
532	  return parsed.gaps.map((gap: unknown, index: number) => {
533	    if (!isRecord(gap)) {
534	      throw new Error(`Malformed bootstrap gap at index ${index + 1}`);
535	    }
536	    return {
537	      id: requireGapString(gap, "id"),
538	      title: optionalGapString(gap, "title"),
539	      status: requireGapString(gap, "status"),
540	      disposition: requireGapString(gap, "disposition"),
541	      linked_work_item: optionalGapString(gap, "linked_work_item") || null,
542	      verification_target: optionalGapString(gap, "verification_target") || null,
543	      source_artifacts: optionalGapStringList(gap, "source_artifacts")
544	    };
