548	function findActiveGap(gaps: RawGap[], activeWorkItemId: string): RawGap {
549	  const linked = gaps.find(
550	    (gap) => gap.linked_work_item === activeWorkItemId && gap.status !== "resolved"
551	  );
552	  if (!linked) {
553	    throw new Error(
554	      `Session context blocked: no active bootstrap gap linked to ${activeWorkItemId}`
555	    );
556	  }
557	  return linked;
558	}
559	
560	function buildBlockers(gaps: RawGap[]) {
561	  return gaps
562	    .filter((gap) => gap.status !== "resolved")
563	    .map((gap) => ({
564	      id: gap.id,
565	      status: gap.disposition,
566	      source: BOOTSTRAP_GAPS_PATH,
567	      title: gap.title
568	    }));
569	}
570	
571	function buildRequiredEvidencePaths(workItemId: string) {
572	  return STAGE_EVIDENCE_INFOS.map((info) => ({
573	    path: buildEvidenceSource(workItemId, info.filename),
574	    stage: info.stageLabel
575	  }));
576	}
577	
578	function buildEvidenceSource(workItemId: string, filename: string) {
579	  return `docs/work/${workItemId}/${filename}`;
580	}
581	
582	function normalizePhase(phase: string) {
583	  const normalized = phase.replace(/\.$/, "");
584	  return normalized.startsWith("Phase ") ? normalized : `Phase ${normalized}`;
585	}
586	
587	function normalizeText(value: string) {
588	  return value
589	    .replace(/`/g, "")
590	    .replace(/\s+/g, " ")
591	    .trim();
592	}
593	
594	function normalizeForComparison(value: string) {
595	  return normalizeText(value)
596	    .replace(/[.;:]/g, "")
597	    .replace(/\s+-\s+/g, " ")
598	    .toLowerCase();
599	}
600	
601	function nextActionsAgree(first: string, second: string, workItemId: string | null) {
602	  const normalizedFirst = normalizeForComparison(first);
603	  const normalizedSecond = normalizeForComparison(second);
604	
605	  if (
606	    normalizedFirst === normalizedSecond ||
607	    normalizedFirst.includes(normalizedSecond) ||
608	    normalizedSecond.includes(normalizedFirst)
609	  ) {
610	    return true;
611	  }
612	
613	  if (workItemId === null) return false;
614	
615	  const workItem = workItemId.toLowerCase();
616	  if (
617	    normalizedFirst.includes(workItem) &&
618	    normalizedSecond.includes(workItem) &&
619	    matchingStage(normalizedFirst, normalizedSecond)
620	  ) {
621	    return true;
622	  }
623	
624	  return false;
625	}
626	
627	function matchingStage(first: string, second: string) {
628	  const firstStages = extractStageNumbers(first);
629	  const secondStages = extractStageNumbers(second);
630	  return firstStages.some((stage) => secondStages.includes(stage));
631	}
632	
633	function extractStageNumbers(value: string) {
634	  return Array.from(value.matchAll(/\bstage\s+(\d+)\b/g)).map((match) =>
635	    String(match[1])
636	  );
637	}
638	
639	function requireGapString(record: Record<string, unknown>, field: string) {
640	  const value = record[field];
641	  if (typeof value !== "string" || value.trim().length === 0) {
642	    throw new Error(`Malformed bootstrap gap: missing required field: ${field}`);
643	  }
644	  return value.trim();
645	}
646	
647	function optionalGapString(record: Record<string, unknown>, field: string) {
648	  const value = record[field];
649	  if (typeof value !== "string") {
650	    return "";
651	  }
652	  return value.trim();
653	}
654	
655	function optionalGapStringList(record: Record<string, unknown>, field: string): string[] {
656	  const value = record[field];
657	  if (!Array.isArray(value)) return [];
658	  return value.filter((item): item is string => typeof item === "string").map((s) => s.trim());
659	}
660	
661	function isRecord(value: unknown): value is Record<string, unknown> {
662	  return typeof value === "object" && value !== null && !Array.isArray(value);
663	}
664	
665	function isMissingPathError(error: unknown) {
666	  return error instanceof Error && "code" in error && error.code === "ENOENT";
